@page "/directory"
@rendermode InteractiveServer
@inject IEmployeeService EmployeeService

<PageTitle>Employee Directory</PageTitle>

<div class="directory-page">
    @* Top Summary Bar *@
    <div class="kpi-bar">
        <div class="kpi-card">
            <span class="kpi-value">@totalEmployees</span>
            <span class="kpi-label">Total Employees</span>
        </div>
        <div class="kpi-card">
            <span class="kpi-value">@totalDepartments</span>
            <span class="kpi-label">Departments</span>
        </div>
        <div class="kpi-card">
            <span class="kpi-value">@averageTenure.ToString("F1")</span>
            <span class="kpi-label">Avg Tenure (yrs)</span>
        </div>
        <div class="kpi-card">
            <span class="kpi-value">@totalLocations</span>
            <span class="kpi-label">Locations</span>
        </div>
    </div>

    @* Main Content *@
    <div class="directory-content">
        @* Left Sidebar *@
        <aside class="sidebar">
            <div class="filters">
                <input type="text" placeholder="Search by name..." @bind="searchQuery" @bind:event="oninput" class="filter-input" />

                <select @bind="selectedDepartment" class="filter-input">
                    <option value="">All Departments</option>
                    @foreach (var dept in departments)
                    {
                        <option value="@dept">@dept</option>
                    }
                </select>

                <select @bind="selectedLocation" class="filter-input">
                    <option value="">All Locations</option>
                    @foreach (var loc in locations)
                    {
                        <option value="@loc">@loc</option>
                    }
                </select>

                <div class="filter-buttons">
                    <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
                    <button class="btn btn-secondary" @onclick="ClearFilters">Clear Filters</button>
                </div>
            </div>

            <div class="employee-list">
                @foreach (var emp in employees)
                {
                    <div class="employee-card @(selectedEmployee?.Id == emp.Id ? "selected" : "")" @onclick="() => SelectEmployee(emp)">
                        <div class="avatar-small">@GetInitials(emp.Name)</div>
                        <div class="employee-card-info">
                            <span class="employee-card-name">@emp.Name</span>
                            <span class="employee-card-title">@emp.Title</span>
                            <span class="badge" style="background-color: @GetDepartmentColor(emp.Department)">@emp.Department</span>
                        </div>
                    </div>
                }
            </div>
        </aside>

        @* Main Detail Area *@
        <main class="detail-panel">
            @if (selectedEmployee is null)
            {
                <div class="placeholder-message">
                    <span>Select an employee to view details</span>
                </div>
            }
            else
            {
                <div class="detail-header">
                    <div class="avatar-large">@GetInitials(selectedEmployee.Name)</div>
                    <div class="detail-header-info">
                        <h2>@selectedEmployee.Name</h2>
                        <p class="detail-title">@selectedEmployee.Title</p>
                        <span class="badge" style="background-color: @GetDepartmentColor(selectedEmployee.Department)">@selectedEmployee.Department</span>
                        <p class="detail-location">📍 @selectedEmployee.Location</p>
                    </div>
                </div>

                <div class="info-grid">
                    <div class="info-item">
                        <span class="info-label">Email</span>
                        <span class="info-value">@selectedEmployee.Email</span>
                    </div>
                    <div class="info-item">
                        <span class="info-label">Hire Date</span>
                        <span class="info-value">@selectedEmployee.HireDate.ToString("MMMM dd, yyyy")</span>
                    </div>
                    <div class="info-item">
                        <span class="info-label">Tenure</span>
                        <span class="info-value">@GetTenureYears(selectedEmployee.HireDate) years</span>
                    </div>
                    <div class="info-item">
                        <span class="info-label">Manager</span>
                        <span class="info-value">@selectedEmployee.ManagerName</span>
                    </div>
                </div>

                <div class="direct-reports-section">
                    <h3>Direct Reports</h3>
                    @if (directReports is null)
                    {
                        <p>Loading...</p>
                    }
                    else if (directReports.Count == 0)
                    {
                        <p>No direct reports</p>
                    }
                    else
                    {
                        <div class="direct-reports-list">
                            @foreach (var report in directReports)
                            {
                                <div class="employee-card clickable" @onclick="() => SelectEmployee(report)">
                                    <div class="avatar-small">@GetInitials(report.Name)</div>
                                    <div class="employee-card-info">
                                        <span class="employee-card-name">@report.Name</span>
                                        <span class="employee-card-title">@report.Title</span>
                                        <span class="badge" style="background-color: @GetDepartmentColor(report.Department)">@report.Department</span>
                                    </div>
                                </div>
                            }
                        </div>
                    }
                </div>
            }
        </main>
    </div>

    @* Footer *@
    <footer class="directory-footer">
        <span>Showing @employees.Count of @totalEmployees employees</span>
    </footer>
</div>

