    font-weight: 500;
}

/* Direct Reports */
.direct-reports-section {
    margin-top: 1.5rem;
}

.direct-reports-section h3 {
    margin: 0 0 1rem 0;
    font-size: 1.1rem;
    color: #1a1a2e;
}

.direct-reports-list {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
    gap: 0.75rem;
}

.direct-reports-list .employee-card {
    background: #fff;
    border: 1px solid #e9ecef;
    border-radius: 8px;
}

.direct-reports-list .employee-card:hover {
    border-color: #4a6cf7;
    background: #f0f4ff;
}

/* Footer */
.directory-footer {
    padding: 0.75rem 1.5rem;
